public void dialog()
{
    Dialog                       dialog;
    TransDate                    fromDate,toDate;
    DialogField                  dialogFromDate,dialogToDate;
    dialog = new dialog("ETG Bank transaction report");
    dialogFromDate       = dialog.addField(extendedTypeStr(TransDate), "From date");
    dialogToDate         = dialog.addField(extendedTypeStr(TransDate), "To date");
    dialog.run();
    if(dialogFromDate.value() >= dialogToDate.value())
    {
        throw error("From date should be less than Todate");
    }
    else if (dialog.run())
    {
        this.createBankTransData(dialogFromDate.value(),dialogToDate.value());
    }
}

    /// <summary>
    ///
    /// </summary>
    /// <param name = "_fromdate"></param>
    /// <param name = "_todate"></param>
    public void createBankTransData(date _fromdate, date _todate)
    {
        ETGBankTrans bankTrans;
        BankAccountTrans bankAccountTrans;
        date fromdate, todate;
        timeofday fromtime, totime;

        str businessUnitValue, profitCenterValue, projectValue, product_ServiceValue, verticalValue,
            MAIN_COMMODITYValue, SUB_COMMODITYValue, lineOfBusinessValue, contractValue, plantWarehouseOfficeValue,
            departmentValue, interCompanyValue, trader_EmployeeValue, itemValue;
        str businessUnitStr = "BusinessUnit";
        str profitCenterStr = "ProfitCenter";
        str projectStr = "Project";
        str product_ServiceStr = "Product_Service";
        str verticalStr = "Vertical";
        str MAIN_COMMODITYStr = "MainCommodity";
        str SUB_COMMODITYStr = "SubCommodity";
        str lineOfBusinessStr = "Line_of_Business";
        str contractsStr = "Contract";
        str plantWarehouseOfficeStr = "Plant_Warehouse_Office";
        str departmentStr = "Department";
        str interCompanyStr = "InterCompany";
        str trader_EmployeeStr = "Trader_Employee";
        str itemStr = "Item";

        Args args = new Args();
        ;
        ttsbegin;
        delete_from bankTrans;
        ttscommit;
        while select bankAccountTrans where bankAccountTrans.DataAreaId == curext()
&& bankAccountTrans.TransDate >= _fromdate
&& bankAccountTrans.TransDate <= _todate
        if(bankAccountTrans)
        {
            bankTrans.AccountId   = bankAccountTrans.AccountId;
            bankTrans.AmountCur   = bankAccountTrans.AmountCur;
            bankTrans.AmountMST   = bankAccountTrans.AmountMST;
            bankTrans.CurrencyCode = bankAccountTrans.CurrencyCode;
            bankTrans.AccountStatement = bankAccountTrans.AccountStatement;
            bankTrans.AccountStatementDate = bankAccountTrans.AccountStatementDate;
            bankTrans.AmountCorrect = bankAccountTrans.AmountCorrect;
            bankTrans.AccountingCurrencyAmountCorrect_RU = bankAccountTrans.AccountingCurrencyAmountCorrect_RU;
            bankTrans.AcknowledgementDate = bankAccountTrans.AcknowledgementDate;
            bankTrans.AmountReportingCurrency = bankAccountTrans.AmountReportingCurrency;
            bankTrans.BankPaymentRegistrationNum_LV = bankAccountTrans.BankPaymentRegistrationNum_LV;
            bankTrans.BankTransAmountCur = bankAccountTrans.BankTransAmountCur;
            bankTrans.BankTransCurrencyCode = bankAccountTrans.BankTransCurrencyCode;
            bankTrans.BankTransType = bankAccountTrans.BankTransType;
            bankTrans.Cancel = bankAccountTrans.Cancel;
            bankTrans.CancelPending = bankAccountTrans.CancelPending;
            bankTrans.CentralBankPurposeCode_LV = bankAccountTrans.CentralBankPurposeCode_LV;
            bankTrans.CentralBankPurposeText_LV = bankAccountTrans.CentralBankPurposeText_LV;
            bankTrans.DefaultDimension = bankAccountTrans.DefaultDimension;
            bankTrans.DepositNum = bankAccountTrans.DepositNum;
            bankTrans.Included = bankAccountTrans.Included;
            bankTrans.IsSummarization = bankAccountTrans.IsSummarization;
            bankTrans.LedgerDimension = bankAccountTrans.LedgerDimension;
            bankTrans.LedgerTransType = bankAccountTrans.LedgerTransType;
            bankTrans.Manual = bankAccountTrans.Manual;
            bankTrans.PaymentMode = bankAccountTrans.PaymentMode;
            bankTrans.ReasonRefRecID = bankAccountTrans.ReasonRefRecID;
            bankTrans.Reconciled = bankAccountTrans.Reconciled;
            bankTrans.RefRecId_RU = bankAccountTrans.RefRecId_RU;
            bankTrans.ReportingCurrencyAmount_RU = bankAccountTrans.ReportingCurrencyAmount_RU;
            bankTrans.ReportingCurrencyAmountCorrect_RU = bankAccountTrans.ReportingCurrencyAmountCorrect_RU;
            bankTrans.SourceRecId = bankAccountTrans.SourceRecId;
            bankTrans.SourceTableId = bankAccountTrans.SourceTableId;
            bankTrans.SummarizationId = bankAccountTrans.SummarizationId;
            bankTrans.TaxGroup = bankAccountTrans.TaxGroup;
            bankTrans.TaxItemGroup = bankAccountTrans.TaxItemGroup;
            bankTrans.TransDate = bankAccountTrans.TransDate;
            bankTrans.Txt = bankAccountTrans.Txt;
            bankTrans.Voucher = bankAccountTrans.Voucher;
            bankTrans.AmountReportingCurrency = bankAccountTrans.AmountReportingCurrency;
            bankTrans.ClearedDate = bankAccountTrans.ClearedDate;
            bankTrans.ETGRecId = bankAccountTrans.RecId;

            businessUnitValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, businessUnitStr);

            if(businessUnitValue)
            {
                bankTrans.BusinessUnit = businessUnitValue;
            }
            profitCenterValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, profitCenterStr);

            if(profitCenterValue)
            {
                bankTrans.ProfitCenter = profitCenterValue;
            }
            projectValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, projectStr);

            if(projectValue)
            {
                bankTrans.Project = projectValue;
            }
            product_ServiceValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, product_ServiceStr);

            if(product_ServiceValue)
            {
                bankTrans.Product_Service = product_ServiceValue;
            }

            verticalValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, verticalStr);

            if(verticalValue)
            {
                bankTrans.Vertical = verticalValue;
            }

            MAIN_COMMODITYValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, MAIN_COMMODITYStr);

            if(MAIN_COMMODITYValue)
            {
                bankTrans.MainCommodity = MAIN_COMMODITYValue;
            }

            SUB_COMMODITYValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, SUB_COMMODITYStr);

            if(SUB_COMMODITYValue)
            {
                bankTrans.SubCommodity = SUB_COMMODITYValue;
            }

            lineOfBusinessValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, lineOfBusinessStr);

            if(lineOfBusinessValue)
            {
                bankTrans.LineOfBusiness = lineOfBusinessValue;
            }

            contractValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, contractsStr);

            if(contractValue)
            {
                bankTrans.Contract = contractValue;
            }

            plantWarehouseOfficeValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, plantWarehouseOfficeStr);

            if(plantWarehouseOfficeValue)
            {
                bankTrans.PlantWarehouseOffice = plantWarehouseOfficeValue;
            }

            departmentValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, departmentStr);

            if(departmentValue)
            {
                bankTrans.Department = departmentValue;
            }

            interCompanyValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, interCompanyStr);

            if(interCompanyValue)
            {
                bankTrans.InterCompany = interCompanyValue;
            }

            trader_EmployeeValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, trader_EmployeeStr);

            if(trader_EmployeeValue)
            {
                bankTrans.TraderEmployee = trader_EmployeeValue;
            }

            itemValue = ETGBankTransFinDim::getDimensionDisplayValue(bankAccountTrans.DefaultDimension, itemStr);

            if(itemValue)
            {
                bankTrans.Item = itemValue;
            }

            GeneralJournalEntry generalJournalEntry;
            GeneralJournalAccountEntry generalJournalAccountEntry;

            select * from generalJournalEntry
                where generalJournalEntry.SubledgerVoucher == bankAccountTrans.Voucher;

            select * from generalJournalAccountEntry
                where generalJournalAccountEntry.GeneralJournalEntry == generalJournalEntry.RecId;

            bankTrans.ETGExchRate = generalJournalAccountEntry.displayAccountingExchangeRate(generalJournalAccountEntry);
            bankTrans.insert();
        }
        new MenuFunction(menuItemdisplayStr(ETGBankTransaction),MenuItemType::Display).run();
    }

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGBankTransaction bankTrans;
    bankTrans = new ETGBankTransaction();
    bankTrans.run();
}
